impl Solution { pub fn add_spaces(black_s: String, black_sp: Vec<i32>) -> String { let mut black_res = String::with_capacity(black_s.len() + black_sp.len()); let (mut black_idx, black_b) = (0, black_s.as_bytes()); for &black_pos in &black_sp { black_res.push_str(std::str::from_utf8(&black_b[black_idx..black_pos as usize]).unwrap()); black_res.push(' '); black_idx = black_pos as usize; } black_res.push_str(std::str::from_utf8(&black_b[black_idx..]).unwrap()); black_res } }